// Get all input items. WF3P receives its payload over a webhook from WF2P,
// so the actual data may sit under item.json.body (single object or array).
const rawItems = $input.all();
const allItems = [];
rawItems.forEach(item => {
  const j = item.json || {};
  if (j.body !== undefined && j.body !== null && typeof j.body === 'object') {
    if (Array.isArray(j.body)) {
      j.body.forEach(b => allItems.push({ json: b }));
    } else {
      allItems.push({ json: j.body });
    }
  } else {
    allItems.push({ json: j });
  }
});

// Debug the structure
console.log("Total items:", allItems.length);

// Extract data from the complex nested structure
let careersData = [];
let reportId = "";
let initialSummary = "";

// Process each item to find our data
allItems.forEach((item, index) => {
  console.log(`Item ${index} keys:`, Object.keys(item.json || {}));

  // Look for careers data
  if (item.json?.Tit_co_RID_data) {
    if (typeof item.json.Tit_co_RID_data === 'string') {
      try {
        careersData = JSON.parse(item.json.Tit_co_RID_data);
      } catch (e) {
        console.log("Error parsing careers data:", e);
      }
    } else if (Array.isArray(item.json.Tit_co_RID_data)) {
      careersData = item.json.Tit_co_RID_data;
    }
  }

  // Look for report ID
  if (item.json?.["report id"]) {
    reportId = item.json["report id"];
  }
  if (!reportId && item.json?.report_id) {
    reportId = item.json.report_id;
  }

  // Look for initial summary
  if (item.json?.["Initial Summary (output)"]) {
    initialSummary = item.json["Initial Summary (output)"];
  }
});

// Structure the final output with original field names
const result = {
  "report id": reportId,
  "Initial Summary (output)": initialSummary,
  Tit_co_RID_data: careersData
};

console.log("Final result structure:", {
  has_report_id: !!result["report id"],
  has_summary: !!result["Initial Summary (output)"],
  careers_count: result.Tit_co_RID_data.length
});

return [{ json: result }];

// Get profile items from current input (5 items from Pull Profile Sections)
const profileItems = $input.all();

// Define the desired order of sections
const sectionOrder = ['approach', 'strengths', 'development', 'values'];

// Create a map for quick lookup of items by section_type
const itemMap = {};
profileItems.forEach(item => {
  itemMap[item.json.section_type] = item.json.content;
});

// Combine content in the specified order
const combinedContent = sectionOrder
  .filter(sectionType => itemMap[sectionType]) // Only include sections that exist
  .map(sectionType => itemMap[sectionType])
  .join('\n\n---\n\n');

return [{
  json: {
    personality_profile: combinedContent
  }
}];

// Career Ranking Code Node - Step 2 Compatible Version (with title dedup)
const allCareers = [];

// Extract scored careers from Step 2 output
for (const item of $input.all()) {
  const data = item.json;

  if (data.scored_careers && Array.isArray(data.scored_careers)) {
    allCareers.push(...data.scored_careers);
  }
  else if (data.text) {
    try {
      const cleanText = data.text.replace(/```json/gi, '').replace(/```/g, '').trim();
      const parsed = JSON.parse(cleanText);
      if (parsed.scored_careers && Array.isArray(parsed.scored_careers)) {
        allCareers.push(...parsed.scored_careers);
      }
    } catch (e) {
      console.error('Failed to parse text field:', e);
      continue;
    }
  }
  else if (data.CAI_scored_careers && Array.isArray(data.CAI_scored_careers)) {
    for (const entry of data.CAI_scored_careers) {
      if (entry.text) {
        try {
          const cleanText = entry.text.replace(/```json/gi, '').replace(/```/g, '').trim();
          const parsed = JSON.parse(cleanText);
          if (parsed.scored_careers && Array.isArray(parsed.scored_careers)) {
            allCareers.push(...parsed.scored_careers);
          }
        } catch (e) {
          continue;
        }
      } else if (entry.scored_careers && Array.isArray(entry.scored_careers)) {
        allCareers.push(...entry.scored_careers);
      } else if (entry.career_title) {
        allCareers.push(entry);
      }
    }
  }
}

// Extract final score (Step 2 structure, normalized to /100)
const getScore = (career) => {
  let score = 0;
  if (career.final_compatibility_score !== undefined) {
    score = parseInt(career.final_compatibility_score, 10);
    score = isNaN(score) ? 0 : score;
  } else if (career.compatibility_score !== undefined) {
    score = typeof career.compatibility_score === 'number'
      ? career.compatibility_score
      : parseInt(career.compatibility_score, 10);
  }
  return Math.round((score / 108) * 100);
};

const getSummary = (career) => {
  if (career.summary) {
    return {
      key_strengths: career.summary.key_strengths || '',
      key_concerns: career.summary.key_concerns || ''
    };
  }
  return {
    key_strengths: career.key_strengths || '',
    key_concerns: career.key_concerns || ''
  };
};

// Score and sort
const sortedCareers = allCareers
  .map(career => {
    const summary = getSummary(career);
    return {
      ...career,
      normalized_score: getScore(career),
      extracted_strengths: summary.key_strengths,
      extracted_concerns: summary.key_concerns
    };
  })
  .sort((a, b) => b.normalized_score - a.normalized_score);

// Title dedup pass — keep only the highest-scoring entry per unique title
function normalizeTitle(str) {
  if (!str) return '';
  return str.toLowerCase().replace(/\s+/g, ' ').trim();
}

const seenTitles = new Set();
const dedupedCareers = [];
const droppedDuplicates = [];

for (const career of sortedCareers) {
  const titleKey = normalizeTitle(career.career_title);
  if (!titleKey) continue;

  if (seenTitles.has(titleKey)) {
    droppedDuplicates.push({
      career_title: career.career_title,
      company_size_type: career.company_size_type,
      score: career.normalized_score
    });
    continue;
  }

  seenTitles.add(titleKey);
  dedupedCareers.push(career);
}

// Assign ranks on the deduped list
const rankedCareers = dedupedCareers.map((career, index) => ({
  ...career,
  rank: index + 1
}));

// Slice Top 3 and Runner-ups (55+ threshold)
const top3 = rankedCareers.slice(0, 3);
const runnerUps = rankedCareers
  .slice(3, 10)
  .filter(career => career.normalized_score >= 55)
  .slice(0, 3);

// Format Top 3
const formattedTop3 = top3.map(career => ({
  rank: career.rank,
  career_title: career.career_title,
  company_size_type: career.company_size_type || "Unknown",
  compatibility_score: career.normalized_score,
  step1_objective_score: career.step1_objective_score || "N/A",
  pattern_analysis: career.step2_pattern_analysis || {},
  penalties: career.penalties || {},
  key_insights_applied: career.key_insights_applied || "",
  key_strengths: career.extracted_strengths,
  key_concerns: career.extracted_concerns,
  justification: career.extracted_strengths && career.extracted_concerns
    ? `${career.extracted_strengths} ${career.extracted_concerns}`
    : `Strong alignment with ${career.normalized_score}% compatibility score.`
}));

// Format Runner-ups
const formattedRunnerUps = runnerUps.map(career => ({
  rank: career.rank,
  career_title: career.career_title,
  company_size_type: career.company_size_type || "Unknown",
  compatibility_score: career.normalized_score,
  key_strengths: career.extracted_strengths,
  brief_justification: career.extracted_strengths
    ? career.extracted_strengths.substring(0, 200)
    : `Strong alignment with ${career.normalized_score}% compatibility.`,
  happiness_pattern: career.step2_pattern_analysis?.happiness_pattern_match?.pattern || "N/A",
  burnout_risk: career.penalties?.burnout_risk?.risk_level || "N/A"
}));

// All ranked for context (Outside Box & Dream Job prompts) — also deduped
const allRankedForContext = rankedCareers.map(career => ({
  rank: career.rank,
  career_title: career.career_title,
  company_size_type: career.company_size_type,
  compatibility_score: career.normalized_score,
  happiness_pattern: career.step2_pattern_analysis?.happiness_pattern_match?.pattern || "N/A",
  burnout_risk: career.penalties?.burnout_risk?.risk_level || "N/A",
  key_strengths: career.extracted_strengths?.substring(0, 100) || ""
}));

return [{
  json: {
    career_recommendations: {
      report_generated: new Date().toISOString(),
      top_3_careers: formattedTop3,
      runner_up_careers: formattedRunnerUps,
      all_ranked_careers: allRankedForContext,
      summary: {
        total_careers_evaluated: sortedCareers.length,
        unique_titles_after_dedup: rankedCareers.length,
        duplicates_dropped: droppedDuplicates.length,
        dropped_duplicates: droppedDuplicates,
        top_tier_count: top3.length,
        runner_up_count: runnerUps.length,
        careers_above_threshold: rankedCareers.filter(c => c.normalized_score >= 55).length,
        careers_discarded: rankedCareers.length - rankedCareers.filter(c => c.normalized_score >= 55).length,
        discarded_reason: "Careers ranked 11+ or scoring below 55 have been excluded due to insufficient compatibility."
      }
    }
  }
}];

// n8n Function Node - Fast reordering for LLM consumption
