});

// Get report_id from upstream node
const reportId = $node["Pull Profile Sections"].json.report_id;
// Get the outside box careers text from the upstream node
const fullText = $json.text;

// Subheaders to convert to h5 tags
const __lang = ($('Pull Profile Sections').first().json.language === 'nl') ? 'nl' : 'en';
const OUTSIDE_BOX_SUBHEADERS_ALL = {
  en: ["Overview", "Why this might be a fit", "Path Type & Reality", "AI Impact on this role"],
  nl: ["Overzicht", "Waarom dit bij je past", "Type pad & realiteit", "AI-impact op deze rol"]
};
const OUTSIDE_BOX_SUBHEADERS = OUTSIDE_BOX_SUBHEADERS_ALL[__lang];

// Function to format subheaders to h5 tags and bold AI rating
function formatSubheaders(content) {
  let formatted = content;

  // Convert subheaders to h5 tags
  OUTSIDE_BOX_SUBHEADERS.forEach(subheader => {
    // Match subheader with optional markdown bold (**), colon, or newline
    const regex = new RegExp(`(^|\\n)\\*?\\*?${subheader}\\*?\\*?:?\\s*`, 'gi');
    formatted = formatted.replace(regex, `$1<h5>${subheader}</h5>\n\n`);
  });

  // Bold the AI impact rating (e.g., "Augmented -", "At Risk -", "Displaced -")
  formatted = formatted.replace(/\n(Minimal|Moderate|High|Severe|Critical|Augmented|At Risk|Displaced|Enhanced|Transformed)(\s*-)/gi, '\n<strong>$1</strong>$2');

  // Clean up any leftover markdown bold markers
  formatted = formatted.replace(/\*\*(.*?)\*\*/g, '$1');

  return formatted.trim();
}

// Function to extract title and return cleaned content
function parseCareer(content) {
  const lines = content.trim().split('\n');
  let title = '';
  let contentStartIndex = 0;

  // Look for title patterns
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();

    // Match "1. Title Name" or "#### 1. Title" patterns
    if (line.match(/^#{0,4}\s*\d+\.\s+.+$/)) {
      title = line.replace(/^#{0,4}\s*\d+\.\s+/, '').trim();
      contentStartIndex = i + 1;
      break;
    }
  }

  // Strip any markdown bold/italic markers the model wrapped the title in
  // (e.g. "**Game Designer**" -> "Game Designer") so they don't leak into
  // the <strong> tag and render as literal asterisks. Titles never contain *.
  title = title.replace(/\*/g, '').trim();

  // Skip empty lines after title
  while (contentStartIndex < lines.length && lines[contentStartIndex].trim() === '') {
    contentStartIndex++;
  }

  // Get remaining content (everything after title)
  const rawContent = lines.slice(contentStartIndex).join('\n').trim();
  const formattedContent = formatSubheaders(rawContent);

  return {
    title: title || 'Outside Box Career',
    content: formattedContent
  };
}

// Split the content by career sections - matches "1.", "2.", "3." at start of line
// Uses lookahead to keep the delimiter with the following section
const careerSections = fullText.split(/(?=^\d+\.\s+)/m);

// Filter out empty sections and trim whitespace
const cleanSections = careerSections.filter(section => section.trim().length > 0);

// Map each section to the required Supabase format
const records = cleanSections.map((section, index) => {
  const parsed = parseCareer(section);
  const moveMatch = section.match(/<!--move:(.*?)-->/i);
  const move = moveMatch ? moveMatch[1].trim() : null;
  const content = parsed.content.replace(/<!--move:.*?-->/gi, '').trim();

  return {
    json: {
      title: `<h3><strong>${parsed.title}</strong></h3>`,
      content: content,
      metadata: move ? { move } : null,
      report_id: reportId,
      section_type: "outside_box",
      order_number: index + 1,
      language: __lang
    }
  };
});

return records;

