// Get careers from direct input
const careers = $input.all().map(item => item.json);

// Get init summary from the other node (no direct connection needed)
const initSummaryContent = $("Pull Init Summary").first().json.content || '';

const batchSize = 5;
const batches = [];

for (let i = 0; i < careers.length; i += batchSize) {
  const careerBatch = careers.slice(i, i + batchSize);

  batches.push({
    json: {
      careers: careerBatch,
      init_summary: initSummaryContent,
      batch_info: {
        batch_number: Math.floor(i / batchSize) + 1,
        total_batches: Math.ceil(careers.length / batchSize),
        careers_in_batch: careerBatch.length
      }
    }
  });
}

return batches;

// Combine all data WF4 needs and pass directly (no Supabase intermediary)
const ranking = $('Ranking').first().json;
const reportId = $('Add structure').first().json['report id'];
const initSummaryContent = $('Pull Init Summary').first().json.content;
const interestsText = $('Extract Interests and history').first().json.text;
const oobText = $('Outside Of Box Analysis').first().json.text || '';

const top3 = ranking.career_recommendations?.top_3_careers || [];
const runnerUps = ranking.career_recommendations?.runner_up_careers || [];
const allRanked = ranking.career_recommendations?.all_ranked_careers || [];

return [{
  json: {
    report_id: reportId,
    top_3_careers: top3,
    runner_up_careers: runnerUps,
    all_ranked_careers: allRanked,
    interests_history_text: interestsText,
    top_3_careers_str: JSON.stringify(top3, null, 2),
    runner_up_careers_str: JSON.stringify(runnerUps, null, 2),
    outside_box_careers_str: oobText,
    init_summary_content: initSummaryContent
  }
}];

// Pull all four inputs explicitly. n8n waits for each referenced
// node to finish before this code runs, so we get them all in sync.

const enrichedCareers = $('content in order').all().map(i => i.json);
const step1Output = $('Step 1 scores').first().json['Step 1 scores'] || [];
const personality = $('Combine Profile sections').first().json;
const sentimentExtract = $('Renaming evidence').first().json;

return [{
  json: {
    "Step 2 input": [
      { "evidence extract": sentimentExtract.text || sentimentExtract['evidence extract'] || sentimentExtract },
      { "Step 1 scores": step1Output },
      { "personality_profile": personality.personality_profile || personality },
      { "enriched_careers": enrichedCareers }
    ]
  }
}];

// "Already considered" namespace for the OOB prompt: each suitable-15 career's
// main title + its alternate titles, so OOB can't echo a presented role's alt
// (e.g. "Program Director" is an alt of "Senior Program Manager, Social Impact").
const enriched = $('Pull enriched').all().map(i => i.json);
const covered = enriched
  .filter(c => c && c.career_title)
  .map(c => {
    let alts = c.alternate_titles;
    if (typeof alts === 'string') { try { alts = JSON.parse(alts); } catch { alts = []; } }
    if (!Array.isArray(alts)) alts = [];
    return { title: c.career_title, alternate_titles: alts };
  });
return [{ json: { covered_titles: JSON.stringify(covered, null, 2) } }];
